section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/judge-calibration-report",
  "type": "object",
  "required": ["holdout", "judge", "metrics", "confusion", "decision"],
  "properties": {
    "holdout": {
      "type": "object",
      "required": ["path", "size", "raters", "labels"],
      "properties": {
        "path": {"type": "string"},
        "size": {"type": "integer", "minimum": 30},
        "raters": {"type": "integer", "minimum": 1},
        "labels": {"type": "array", "minItems": 2, "items": {"type": "string"}}
      }
    },
    "judge": {
      "type": "object",
      "required": ["model", "prompt_hash", "run_at"],
      "properties": {
        "model": {"type": "string"},
        "prompt_hash": {"type": "string", "pattern": "^[a-f0-9]{40}$"},
        "run_at": {"type": "string", "format": "date-time"}
      }
    },
    "metrics": {
      "type": "object",
      "required": ["kappa", "accuracy", "false_pass_rate", "false_fail_rate"],
      "properties": {
        "kappa": {"type": "number", "minimum": -1, "maximum": 1},
        "accuracy": {"type": "number", "minimum": 0, "maximum": 1},
        "false_pass_rate": {"type": "number", "minimum": 0, "maximum": 1},
        "false_fail_rate": {"type": "number", "minimum": 0, "maximum": 1}
      }
    },
    "confusion": {
      "type": "object",
      "description": "labels x labels integer counts; row=ref, col=judge"
    },
    "decision": {"enum": ["ship", "revise_prompt", "revise_holdout", "block"]}
  }
}
